1	/**
2	 * EDT-01 — grip + temp-dimension overlay.
3	 *
4	 * 2D HTML/SVG overlay rendered above the Three.js canvas. The grip
5	 * shapes (square / circle / arrow) sit on top of the elements; the
6	 * temp-dimension layer paints faint blue lines toward the nearest
7	 * neighbours with a small lock chip. Pure presentational — pointer
8	 * handlers are passed in by `PlanCanvas`.
9	 */
10	import type { CSSProperties, MouseEvent as ReactMouseEvent } from 'react';
11	
12	import type { GripDescriptor } from './gripProtocol';
13	import type { TempDimTarget } from './tempDimensions';
14	
15	export interface ScreenPoint {
16	  pxX: number;
17	  pxY: number;
18	}
19	
20	export interface GripLayerProps {
21	  grips: GripDescriptor[];
22	  worldToScreen: (xy: { xMm: number; yMm: number }) => ScreenPoint;
23	  onGripPointerDown: (
24	    grip: GripDescriptor,
25	    ev: ReactMouseEvent<HTMLDivElement> | PointerEvent,
26	  ) => void;
27	  /** Live draft preview while a wall grip is being dragged. */
28	  draftWall?: { start: { xMm: number; yMm: number }; end: { xMm: number; yMm: number } } | null;
29	  /** Active grip id — paints a slightly emphasised handle so the user
30	   *  can see which grip is being dragged. */
31	  activeGripId?: string | null;
32	}
33	
34	const GRIP_PX = 12;
35	
36	function gripStyle(
37	  pos: ScreenPoint,
38	  shape: GripDescriptor['shape'],
39	  active: boolean,
40	): CSSProperties {
41	  const half = GRIP_PX / 2;
42	  const base: CSSProperties = {
43	    position: 'absolute',
44	    left: pos.pxX - half,
45	    top: pos.pxY - half,
46	    width: GRIP_PX,
47	    height: GRIP_PX,
48	    pointerEvents: 'auto',
49	    cursor: shape === 'arrow' ? 'ew-resize' : 'grab',
50	    background: active ? 'rgba(252,211,77,0.35)' : 'rgba(252,211,77,0.15)',
51	    border: '1.5px solid #fcd34d',
52	    boxSizing: 'border-box',
53	    touchAction: 'none',
54	  };
55	  if (shape === 'circle') {
56	    base.borderRadius = '50%';
57	  }
58	  if (shape === 'arrow') {
59	    // Diamond — distinguishes it from the squares without a sprite.
60	    base.transform = 'rotate(45deg)';
61	  }
62	  return base;
63	}
64	
65	export function GripLayer({
66	  grips,
67	  worldToScreen,
68	  onGripPointerDown,
69	  draftWall,
70	  activeGripId,
71	}: GripLayerProps) {
72	  if (grips.length === 0 && !draftWall) return null;
73	  return (
74	    <div
75	      data-testid="grip-layer"
76	      style={{
77	        position: 'absolute',
78	        inset: 0,
79	        pointerEvents: 'none',
80	      }}
81	    >
82	      {draftWall && (
83	        <DraftWallPreview
84	          start={worldToScreen(draftWall.start)}
85	          end={worldToScreen(draftWall.end)}
86	        />
87	      )}
88	      {grips.map((g) => {
89	        const pos = worldToScreen(g.positionMm);
90	        return (
91	          <div
92	            key={g.id}
93	            data-testid={`grip-${g.id}`}
94	            data-grip-shape={g.shape}
95	            data-grip-axis={g.axis}
96	            title={g.hint ?? g.id}
97	            style={gripStyle(pos, g.shape, activeGripId === g.id)}
98	            onPointerDown={(ev) => {
99	              ev.stopPropagation();
100	              onGripPointerDown(g, ev);
101	            }}
102	          />
103	        );
104	      })}
105	    </div>
106	  );
107	}
108	
109	function DraftWallPreview({ start, end }: { start: ScreenPoint; end: ScreenPoint }) {
110	  const minX = Math.min(start.pxX, end.pxX) - 4;
111	  const minY = Math.min(start.pxY, end.pxY) - 4;
112	  const maxX = Math.max(start.pxX, end.pxX) + 4;
113	  const maxY = Math.max(start.pxY, end.pxY) + 4;
114	  const w = Math.max(1, maxX - minX);
115	  const h = Math.max(1, maxY - minY);
116	  return (
117	    <svg
118	      data-testid="grip-draft-preview"
119	      style={{ position: 'absolute', left: minX, top: minY, pointerEvents: 'none' }}
120	      width={w}
121	      height={h}
122	      viewBox={`${minX} ${minY} ${w} ${h}`}
123	    >
124	      <line
125	        x1={start.pxX}
126	        y1={start.pxY}
127	        x2={end.pxX}
128	        y2={end.pxY}
129	        stroke="#fcd34d"
130	        strokeWidth={2}
131	        strokeDasharray="6 4"
132	      />
133	    </svg>
134	  );
135	}
136	
137	/* ─── Temp-dimension layer ────────────────────────────────────────── */
138	
139	export interface TempDimLayerProps {
140	  targets: TempDimTarget[];
141	  worldToScreen: (xy: { xMm: number; yMm: number }) => ScreenPoint;
142	  onTargetClick: (target: TempDimTarget) => void;
143	  onLockClick: (target: TempDimTarget) => void;
144	  /** EDT-02 — predicate returning whether the target already has a
145	   *  matching `ConstraintElem` in the world. Drives the open- vs
146	   *  filled-padlock glyph swap. */
147	  isLocked?: (target: TempDimTarget) => boolean;
148	}
149	
150	function formatMm(mm: number): string {
151	  if (mm >= 1000) return `${(mm / 1000).toFixed(2)} m`;
152	  return `${Math.round(mm)} mm`;
153	}
154	
155	export function TempDimLayer({
156	  targets,
157	  worldToScreen,
158	  onTargetClick,
159	  onLockClick,
160	  isLocked,
161	}: TempDimLayerProps) {
162	  if (targets.length === 0) return null;
163	  return (
164	    <div
165	      data-testid="temp-dim-layer"
166	      style={{
167	        position: 'absolute',
168	        inset: 0,
169	        pointerEvents: 'none',
170	      }}
171	    >
172	      {targets.map((t) => {
173	        const a = worldToScreen(t.fromMm);
174	        const b = worldToScreen(t.toMm);
175	        const cx = (a.pxX + b.pxX) / 2;
176	        const cy = (a.pxY + b.pxY) / 2;
177	        const minX = Math.min(a.pxX, b.pxX) - 24;
178	        const minY = Math.min(a.pxY, b.pxY) - 24;
179	        const maxX = Math.max(a.pxX, b.pxX) + 24;
180	        const maxY = Math.max(a.pxY, b.pxY) + 24;
181	        const w = Math.max(1, maxX - minX);
182	        const h = Math.max(1, maxY - minY);
183	        return (
184	          <div key={t.id} data-testid={`temp-dim-${t.id}`}>
185	            <svg
186	              style={{
187	                position: 'absolute',
188	                left: minX,
189	                top: minY,
190	                pointerEvents: 'none',
191	              }}
192	              width={w}
193	              height={h}
194	              viewBox={`${minX} ${minY} ${w} ${h}`}
195	            >
196	              <line
197	                x1={a.pxX}
198	                y1={a.pxY}
199	                x2={b.pxX}
200	                y2={b.pxY}
201	                stroke="#7dd3fc"
202	                strokeOpacity={0.55}
203	                strokeWidth={1}
204	                strokeDasharray="4 3"
205	              />
206	            </svg>
207	            <button
208	              type="button"
209	              data-testid={`temp-dim-readout-${t.id}`}
210	              onClick={() => onTargetClick(t)}
211	              style={{
