213	                left: cx - 30,
214	                top: cy - 10,
215	                width: 60,
216	                height: 20,
217	                pointerEvents: 'auto',
218	                cursor: 'pointer',
219	                background: 'rgba(20,28,42,0.75)',
220	                color: '#7dd3fc',
