222	                fontFamily:
223	                  'ui-monospace, SFMono-Regular, "SF Mono", Menlo, Monaco, Consolas, monospace',
224	                border: '1px solid rgba(125,211,252,0.4)',
225	                borderRadius: 3,
226	              }}
227	              title="Click to convert to a persistent dimension"
228	            >
229	              {formatMm(t.distanceMm)}
230	            </button>
231	            {(() => {
232	              const locked = isLocked ? isLocked(t) : false;
233	              return (
