242	                    top: cy - 10,
243	                    width: 18,
244	                    height: 18,
245	                    pointerEvents: 'auto',
246	                    cursor: 'pointer',
247	                    background: locked ? 'rgba(252,211,77,0.85)' : 'rgba(20,28,42,0.75)',
