583	function progressScore(goalText, snap, val) {
584	  const summary = summariseValidate(val);
585	  const elementsBlob = JSON.stringify(snap?.elements ?? {}).toLowerCase();
586	  const keywords = new Set(
587	    (goalText.match(/[A-Za-z_][A-Za-z0-9_]{3,}/g) ?? [])
588	      .filter((w) => !/^\d+$/.test(w))
589	      .map((w) => w.toLowerCase()),
590	  );
591	  let overlap = 0;
592	  for (const kw of keywords) if (elementsBlob.includes(kw)) overlap++;
593	  return -summary.blockingCount * 100 + overlap;
594	}
