def _anchor_xy(elem: dict[str, Any], anchor: str) -> tuple[float, float] | None:
    kind = elem.get("kind")
    if kind == "wall":
        return _wall_anchor_xy(elem, anchor)
    return None


def _distance(p: tuple[float, float], q: tuple[float, float]) -> float:
    return hypot(p[0] - q[0], p[1] - q[1])


def _wall_spine(elem: dict[str, Any]) -> tuple[float, float] | None:
    """Return the (dx, dy) direction vector of a wall spine (unnormalised)."""
    if elem.get("kind") != "wall":
        return None
    s = elem.get("start") or {}
    e = elem.get("end") or {}
    dx = float(e.get("xMm", 0)) - float(s.get("xMm", 0))
    dy = float(e.get("yMm", 0)) - float(s.get("yMm", 0))
    return dx, dy


def _wall_spine_length(elem: dict[str, Any]) -> float | None:
    v = _wall_spine(elem)
    if v is None:
        return None
    return hypot(v[0], v[1])


def _wall_start_xy(elem: dict[str, Any]) -> tuple[float, float] | None:
    if elem.get("kind") != "wall":
        return None
    s = elem.get("start") or {}
    return float(s.get("xMm", 0)), float(s.get("yMm", 0))


def _angle_between(va: tuple[float, float], vb: tuple[float, float]) -> float:
    """Smallest unsigned angle between two direction vectors (radians, 0..π/2)."""
    la = hypot(va[0], va[1])
    lb = hypot(vb[0], vb[1])
    if la < 1e-9 or lb < 1e-9:
        return 0.0
    cos_theta = (va[0] * vb[0] + va[1] * vb[1]) / (la * lb)
    cos_theta = max(-1.0, min(1.0, cos_theta))
    theta = math.acos(cos_theta)
    # Normalise to [0, π/2] so antiparallel walls are treated as parallel.
    if theta > math.pi / 2:
        theta = math.pi - theta
    return theta


def _point_to_line_offset(
    px: float,
    py: float,
    lx: float,
    ly: float,
    dx: float,
    dy: float,
) -> float:
    """Perpendicular distance from point (px,py) to the infinite line through (lx,ly) in direction (dx,dy)."""
    length = hypot(dx, dy)
    if length < 1e-9:
        return hypot(px - lx, py - ly)
    # Cross product magnitude / length = perpendicular distance.
    return abs((px - lx) * dy - (py - ly) * dx) / length

